function minutosDesdeHora(hhmm) {
  const [h, m] = hhmm.split(":").map(Number);
  return h * 60 + m;
}

// Fuente única del "avance general": si el coachee ya se autoevaluó ("qué tan cerca
// sientes que estás de tu objetivo"), ese valor manda en TODAS las vistas (coachee,
// empresa, coach, reportes). Si aún no se ha autoevaluado, se usa el valor de referencia
// generado con sus datos. Así el número nunca difiere según quién lo esté mirando.
function avanceRealDe(coachee) {
  const cercania = coachee.postSesion?.cercania || [];
  if (cercania.length === 0) return coachee.avanceGeneral;
  const ultima = [...cercania].sort((a, b) => b.sesion - a.sesion)[0];
  return ultima.valor * 10;
}

