// Cálculo único de cobros por empresa — usado tanto en el Panel de Negocio (Inicio)
// como en la pestaña Negocio, para que ambos muestren siempre las mismas cifras.
// "monto" (facturable/proyectado) usa las sesiones facturables asignadas a cada coachee.
// "montoRealizadoMes" (para Ingresos del mes) usa únicamente las sesiones YA REALIZADAS
// este mes según el calendario — multiplicadas por la tarifa — y solo cuenta si la empresa está Pagada.
// Cada coachee puede tener su propia tarifa (tarifaPropia) que prevalece sobre la de su empresa —
// esto es clave para "Independientes", donde cada uno negocia su propio precio.
function calcularResumenCobros(coachees, sesionesAgenda = []) {
  const clave = (s) => s.anio * 10000 + s.mes * 100 + s.dia;
  const coacheePorNombre = {};
  coachees.forEach((c) => { coacheePorNombre[c.nombre] = c; });
  const realizadasEsteMes = sesionesAgenda.filter((s) => s.mes === HOY.mes && s.anio === HOY.anio && clave(s) <= clave(HOY));

  return empresasConfig.map((emp) => {
    const coacheesEmpresa = coachees.filter((c) => c.empresa === emp.nombre);
    const tarifaDe = (c) => c.tarifaPropia || emp.tarifa;
    const monto = coacheesEmpresa.reduce((a, c) => a + (c.facturablesMes || 0) * tarifaDe(c), 0);
    const sesionesDeEmpresa = realizadasEsteMes.filter((s) => coacheePorNombre[s.coachee]?.empresa === emp.nombre);
    const sesionesRealizadasMes = sesionesDeEmpresa.length;
    const montoRealizadoMes = sesionesDeEmpresa.reduce((a, s) => a + tarifaDe(coacheePorNombre[s.coachee]), 0);
    return { ...emp, coacheesEmpresa, monto, sesionesRealizadasMes, montoRealizadoMes };
  });
}

