function generarHistorialSesiones(n, competencia) {
  const meses = ["mar", "abr", "may", "jun"];
  const hist = [];
  for (let i = 1; i <= n; i++) {
    hist.push({
      sesion: i,
      fecha: `${2 + i * 2} ${meses[Math.min(3, Math.floor((i - 1) / 3))]}`,
      nivel: Math.min(5, 1 + Math.ceil(i / 2)),
      resumen: `Trabajamos ${competencia.toLowerCase()} aplicado a una situación real de la semana.`,
    });
  }
  return hist;
}

function generarHabito(competencia) {
  return {
    cuando: `Surge una situación que exige ${competencia.toLowerCase()}`,
    enVezDe: "Reaccionar de la forma habitual, sin pausar antes de actuar",
    voyA: "Aplicar la herramienta trabajada en sesión antes de responder",
    obvio: "Recordatorio visual en su espacio de trabajo",
    sencillo: "Un solo paso simple, no un proceso largo",
    atractivo: "Asociarlo a un beneficio personal concreto y visible",
    satisfactorio: "Registrar el logro en su bitácora de avances",
  };
}

function generarPlanEjecucion(n) {
  const pasos = [
    "Diagnóstico inicial de la situación",
    "Definir criterios de acción",
    "Primera práctica guiada",
    "Sostener el cambio en el tiempo",
    "Revisión de resultados con jefatura",
  ];
  const estados = ["Completado", "Completado", "En curso", "Pendiente", "Pendiente"];
  const arr = [];
  for (let i = 0; i < Math.min(n, pasos.length); i++) {
    arr.push({ actividad: pasos[i], inicio: `0${i + 1} jun`, fin: `1${i + 1} jun`, estado: estados[i], objetivoIndex: i % 2 });
  }
  return arr;
}

function generarCoachee(id, nombre, empresaCfg, area, idx) {
  const competencia = COMPETENCIAS_POOL[idx % COMPETENCIAS_POOL.length];
  const objetivoProceso = `Desarrollar ${competencia.toLowerCase()} de forma sostenida en su rol actual`;
  const totalSesiones = [6, 8, 10][idx % 3];
  const hechas = Math.max(1, ((idx * 2) % totalSesiones) + 1);
  const finalizado = hechas === totalSesiones;
  const fase = finalizado ? 2 : hechas > totalSesiones / 2 ? 1 : 0;
  const avanceGeneral = Math.max(10, Math.min(100, Math.round((hechas / totalSesiones) * 100) - (idx % 2 === 0 ? 0 : 6)));
  const satisfaccion = [5, 4, 5, 5, 4][idx % 5];
  const nivelInicial = 1 + (idx % 2);
  const nivelActual = finalizado ? Math.min(5, nivelInicial + 2) : nivelInicial + (hechas > 2 ? 1 : 0);
  const nivelObjetivo = Math.min(5, nivelInicial + 2);
  const resultadoProceso = finalizado ? ["Logrado", "Logrado", "Medianamente logrado"][idx % 3] : null;
  const cargo = CARGO_TEMPLATES[idx % CARGO_TEMPLATES.length].replace("{area}", area);
  const primerNombre = nombre.split(" ")[0].toLowerCase();
  const dominio = empresaCfg.nombre.toLowerCase().replace(/[^a-z]/g, "").slice(0, 14);
  const facturablesMes = [1, 2, 2, 3][idx % 4];

  return {
    id, nombre, empresa: empresaCfg.nombre, cargo,
    jefeDirecto: empresaCfg.jefeGeneral, objetivoProceso, area,
    telefono: `+56 9 ${String(6100 + idx * 137).slice(0, 4)} ${String(2200 + idx * 91).slice(0, 4)}`,
    email: `${primerNombre}@${dominio}.cl`,
    resumenReunionInicial:
      idx % 3 === 0
        ? { texto: `RRHH y jefatura acordaron trabajar ${competencia.toLowerCase()} como foco principal del proceso.`, fecha: "2 mar 2026", autor: "Coach Fernando Ramos" }
        : null,
    postSesion: {
      aprendizajes:
        hechas >= 2
          ? [
              { sesion: hechas - 1, fecha: "reciente", texto: `Empecé a notar cuándo se me activa el patrón contrario a ${competencia.toLowerCase()}.` },
              { sesion: hechas, fecha: "reciente", texto: `Practiqué ${competencia.toLowerCase()} en una situación concreta esta semana.` },
            ]
          : hechas === 1
          ? [{ sesion: 1, fecha: "reciente", texto: `Practiqué ${competencia.toLowerCase()} en una situación concreta esta semana.` }]
          : [],
      utilidad: hechas > 0 ? [{ sesion: hechas, valor: satisfaccion }] : [],
      cercania: hechas > 0 ? [{ sesion: hechas, valor: Math.max(1, Math.min(10, Math.round(avanceGeneral / 10))) }] : [],
      temasProximos: !finalizado ? [{ texto: `Seguir practicando ${competencia.toLowerCase()}`, fecha: "reciente" }] : [],
    },
    fase, sesiones: { hechas, total: totalSesiones }, avanceGeneral, satisfaccion,
    proximaSesion: finalizado ? "Sesión de cierre agendada" : "22 jul, 10:00",
    objetivos: [{ titulo: objetivoProceso, avance: avanceGeneral }],
    notasPrivadas: NOTAS_PRIVADAS_POOL[idx % NOTAS_PRIVADAS_POOL.length],
    historialSesiones: generarHistorialSesiones(hechas, competencia),
    historialCiclos: [],
    resultadoProceso,
    recursosAsignados: [recursos[idx % recursos.length].titulo],
    logros: hechas > 1 ? [{ texto: `Aplicó un ajuste concreto relacionado con ${competencia.toLowerCase()}`, fecha: "reciente" }] : [],
    aprendizajes: [],
    facturablesMes,
    consentimientoInformado: idx % 9 !== 0,
    planDesarrollo: {
      competencia, nivelObjetivo, objetivoGeneral: objetivoProceso,
      objetivosEspecificos: [
        `Aplicar ${competencia.toLowerCase()} en al menos una situación semanal`,
        "Sostener el cambio por al menos 60 días",
      ],
      estadoAprobacion: idx % 6 === 0 ? "Pendiente de aprobación" : "Aprobado",
      comentarioCoach: "",
      nivelInicial, nivelActual, plazo: "30 sep 2026",
      descripcionActual: `Aún no consolida ${competencia.toLowerCase()} de forma sostenida en su día a día.`,
      habito: generarHabito(competencia),
      planEjecucion: generarPlanEjecucion(Math.min(4, hechas + 1)),
      formacion: { Libros: [], Artículos: [recursos[idx % recursos.length].titulo], Videos: [], Podcasts: [] },
    },
    ...(finalizado
      ? {
          reporteFinal: {
            fecha: "reciente", subidoPor: "Coach Fernando Ramos",
            resumen: `Completó su ciclo enfocado en ${competencia.toLowerCase()}, mostrando avances sostenidos frente al diagnóstico inicial.`,
            logros: [`Aplica ${competencia.toLowerCase()} con mayor autonomía en su rol`, "Sostiene el nuevo hábito sin recordatorios externos"],
            recomendacion: "Sostener con revisiones trimestrales breves durante los próximos 6 meses.",
          },
        }
      : {}),
  };
}

function generarCoacheesAdicionales() {
  const cantidadPorEmpresa = { "Andes Minerals": 4, "Viña del Sur": 5, "Banco Cordillera": 7, "Retail Express": 6, "Salud Integral": 7 };
  let idGen = 100;
  let nombreIdx = 0;
  const generados = [];
  empresasConfig.forEach((emp) => {
    const n = cantidadPorEmpresa[emp.nombre] || 0;
    for (let i = 0; i < n; i++) {
      const area = emp.areas[i % emp.areas.length];
      const nombre = NOMBRES_POOL[nombreIdx % NOMBRES_POOL.length];
      nombreIdx++;
      generados.push(generarCoachee(idGen, nombre, emp, area, idGen));
      idGen++;
    }
  });
  return generados;
}

