function generarSesionesAgenda() {
  const base = new Date(2026, 4, 4); // lunes 4 de mayo de 2026
  const patronA = [0, 1, 3, 4]; // lun, mar, jue, vie
  const patronB = [0, 2, 3, 4]; // lun, mié, jue, vie
  const horas = ["09:00", "10:30", "11:30", "15:00", "16:30", "17:30"];
  const sesiones = [{ id: 1, dia: 10, mes: 6, anio: 2026, hora: "11:30", coachee: "María Fernanda Soto", linkVideollamada: LINK_VIDEOLLAMADA }];
  let id = 2;
  let coacheeIdx = 0;
  for (let semana = 0; semana < 14; semana++) {
    const patron = semana % 2 === 0 ? patronA : patronB;
    for (const offsetDia of patron) {
      const f = new Date(base.getTime());
      f.setDate(f.getDate() + semana * 7 + offsetDia);
      if (f.getDate() === 10 && f.getMonth() === 6 && f.getFullYear() === 2026) continue; // no duplicar la sesión ancla de hoy
      const coachee = initialCoacheesData[coacheeIdx % initialCoacheesData.length];
      coacheeIdx++;
      sesiones.push({
        id: id,
        dia: f.getDate(), mes: f.getMonth(), anio: f.getFullYear(),
        hora: horas[id % horas.length],
        coachee: coachee.nombre,
        linkVideollamada: LINK_VIDEOLLAMADA,
      });
      id++;
    }
  }
  return sesiones;
}

const sesionesAgendaIniciales = generarSesionesAgenda();

/* ---------------------------------------------------------
   CONTEXTO — fuente única de datos compartida entre roles
--------------------------------------------------------- */
const CoachingContext = createContext(null);
function useCoaching() {
  return useContext(CoachingContext);
}

function CoachingProvider({ children }) {
  const [coachees, setCoachees] = useState(initialCoacheesData);
  const [sesionesAgenda, setSesionesAgenda] = useState(sesionesAgendaIniciales);
  const [historialCambios, setHistorialCambios] = useState([
    { fecha: "10 jul 2026", hora: "09:12", quien: "Coach Fernando Ramos", texto: "Aprobó el plan de desarrollo de Rodrigo Peña." },
    { fecha: "08 jul 2026", hora: "17:40", quien: "Coach Fernando Ramos", texto: "Asignó el recurso 'Mapa de partes en conflicto interno' a María Fernanda Soto." },
    { fecha: "30 jun 2026", hora: "12:05", quien: "Andes Minerals (RRHH)", texto: "Calificó el proceso de Rodrigo Peña como 'Logrado'." },
  ]);
  const [solicitudesReagendamiento, setSolicitudesReagendamiento] = useState([]);
  const [toast, setToast] = useState(null);

  const mostrarToast = (mensaje) => {
    setToast(mensaje);
    window.clearTimeout(window.__toastTimeout);
    window.__toastTimeout = window.setTimeout(() => setToast(null), 2200);
  };

  const updateCoachee = (id, updater) => {
    setCoachees((prev) =>
      prev.map((c) => (c.id === id ? (typeof updater === "function" ? updater(c) : { ...c, ...updater }) : c))
    );
  };

  const registrarCambio = (texto, quien = "Coach Fernando Ramos") => {
    const ahora = new Date();
    setHistorialCambios((prev) => [
      { fecha: "hoy", hora: ahora.toTimeString().slice(0, 5), quien, texto },
      ...prev,
    ]);
  };

  const crearSolicitudReagendamiento = (sesionId, coacheeNombre, motivo) => {
    setSolicitudesReagendamiento((prev) => [
      { id: Date.now(), sesionId, coacheeNombre, motivo, estado: "Pendiente", respuesta: null },
      ...prev,
    ]);
  };

  const responderConDisponibilidad = (id, texto) => {
    setSolicitudesReagendamiento((prev) =>
      prev.map((s) => (s.id === id ? { ...s, estado: "Respondida", respuesta: { tipo: "opciones", texto } } : s))
    );
  };

  const responderConPropuesta = (id, sesionId, nuevaFecha) => {
    setSesionesAgenda((sa) => sa.map((s) => (s.id === sesionId ? { ...s, ...nuevaFecha } : s)));
    setSolicitudesReagendamiento((prev) =>
      prev.map((s) => (s.id === id ? { ...s, estado: "Respondida", respuesta: { tipo: "propuesta", nuevaFecha } } : s))
    );
  };

  return (
    <CoachingContext.Provider
      value={{
        coachees, updateCoachee, sesionesAgenda, setSesionesAgenda, historialCambios, registrarCambio,
        solicitudesReagendamiento, crearSolicitudReagendamiento, responderConDisponibilidad, responderConPropuesta,
        mostrarToast,
      }}
    >
      {children}
      {toast && (
        <div className="fixed bottom-5 left-1/2 -translate-x-1/2 z-[100] bg-[#121212] text-[#F1EBDD] text-sm px-4 py-2.5 rounded-full shadow-lg flex items-center gap-2 animate-[fadeIn_0.2s_ease]">
          <CheckCircle2 size={14} className="text-[#6B8F71]" />
          {toast}
        </div>
      )}
    </CoachingContext.Provider>
  );
}

