  const temasProximos = (yo.postSesion?.temasProximos || []).slice(0, 2);
  const cercaniaOrdenada = [...(yo.postSesion?.cercania || [])].sort((a, b) => b.sesion - a.sesion);
  const ultimaCercania = cercaniaOrdenada[0];
  const avanceMostrado = ultimaCercania ? `${ultimaCercania.valor * 10}%` : "—";
  const tareasPendientes = [...(yo.planDesarrollo.planEjecucion || [])]
    .filter((a) => a.estado !== "Completado")
