const COLORES_AREA = ["#6B8F71", "#B08D57", "#8AA98F", "#C9A876", "#4F6B54", "#D8C4A0"];

function DistribucionAreaChart({ datos }) {
  const total = datos.reduce((a, d) => a + d.valor, 0);
  return (
    <div className="bg-[#FDFBF7] rounded-2xl border border-[#EDE3D0] shadow-[0_3px_14px_rgba(90,68,40,0.07)] p-4 sm:p-5">
      <div className="flex items-center gap-2 mb-3 sm:mb-4">
        <Users size={16} className="text-[#6B8F71]" />
        <h3 className="font-medium text-[#121212] text-sm sm:text-base">Distribución por departamento</h3>
      </div>
      <div className="flex items-center gap-4 sm:gap-5">
        <div className="relative shrink-0" style={{ width: 130, height: 130 }}>
          <ResponsiveContainer>
            <PieChart>
              <Pie data={datos} dataKey="valor" nameKey="area" innerRadius={38} outerRadius={62} paddingAngle={3} stroke="none">
                {datos.map((d, i) => (
                  <Cell key={i} fill={COLORES_AREA[i % COLORES_AREA.length]} />
                ))}
              </Pie>
              <Tooltip contentStyle={{ fontSize: 12, borderRadius: 8, borderColor: "#E4DCC9" }} />
            </PieChart>
          </ResponsiveContainer>
          <div className="absolute inset-0 flex flex-col items-center justify-center pointer-events-none">
            <span className="text-lg font-mono text-[#121212] leading-none">{total}</span>
            <span className="text-[9px] text-[#8A8270] mt-0.5">coachees</span>
          </div>
        </div>
        <div className="flex-1 min-w-0 space-y-2">
          {datos.map((d, i) => (
            <div key={d.area} className="flex items-center justify-between gap-2 text-xs">
              <span className="flex items-center gap-1.5 text-[#3A3226] min-w-0">
                <span className="w-2 h-2 rounded-full shrink-0" style={{ backgroundColor: COLORES_AREA[i % COLORES_AREA.length] }} />
                <span className="truncate">{d.area}</span>
              </span>
              <span className="font-mono text-[#8A8270] shrink-0">{d.valor} · {Math.round((d.valor / total) * 100)}%</span>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
}

function CompetenciasTrabajadasChart({ equipo }) {
  const [seleccionada, setSeleccionada] = useState(null);
  const counts = {};
  equipo.forEach((c) => {
    const comp = c.planDesarrollo.competencia || "Sin definir";
    counts[comp] = (counts[comp] || 0) + 1;
  });
  const datos = Object.entries(counts)
    .map(([competencia, valor]) => ({ competencia, valor }))
    .sort((a, b) => b.valor - a.valor);
  const max = Math.max(...datos.map((d) => d.valor), 1);
  const coacheesDe = (competencia) => equipo.filter((c) => (c.planDesarrollo.competencia || "Sin definir") === competencia);

  return (
    <div className="bg-[#FDFBF7] rounded-2xl border border-[#EDE3D0] shadow-[0_3px_14px_rgba(90,68,40,0.07)] p-4 sm:p-5">
      <div className="flex items-center gap-2 mb-1">
        <Sparkles size={16} className="text-[#6B8F71]" />
        <h3 className="font-medium text-[#121212] text-sm sm:text-base">Competencias trabajadas</h3>
      </div>
      <p className="text-xs text-[#8A8270] mb-4">Toca una competencia para ver quiénes la están trabajando.</p>
      <div className="space-y-2.5">
        {datos.map((d) => {
          const activo = seleccionada === d.competencia;
          return (
            <div key={d.competencia}>
              <button onClick={() => setSeleccionada(activo ? null : d.competencia)} className="w-full flex items-center gap-3 text-left group">
                <span className="text-xs text-[#3A3226] w-32 sm:w-44 shrink-0 truncate group-hover:text-[#6B8F71] transition-colors">{d.competencia}</span>
                <div className="flex-1 h-3 rounded-full bg-[#EFEAE0] overflow-hidden">
                  <div className="h-full rounded-full bg-[#6B8F71] transition-all" style={{ width: `${(d.valor / max) * 100}%` }} />
                </div>
                <span className="text-xs font-mono text-[#8A8270] w-5 text-right shrink-0">{d.valor}</span>
                <ChevronRight size={13} className={`text-[#B0A78E] shrink-0 transition-transform ${activo ? "rotate-90" : ""}`} />
              </button>
              {activo && (
                <div className="mt-2 ml-2 space-y-1.5 border-l-2 border-[#E4DCC9] pl-3">
                  {coacheesDe(d.competencia).map((c) => (
                    <div key={c.id} className="flex items-center justify-between text-xs">
                      <span className="text-[#3A3226]">{c.nombre}</span>
                      <span className="text-[#8A8270]">{c.area}</span>
                    </div>
                  ))}
                </div>
              )}
            </div>
          );
        })}
      </div>
    </div>
  );
}

