function AbrirNuevoProcesoInline({ nombre }) {
  const [abierto, setAbierto] = useState(false);
  const [enviado, setEnviado] = useState(false);
  const [cargo, setCargo] = useState("");
  const [objetivo, setObjetivo] = useState("");

  return (
    <div className="border-t border-[#EFEAE0] pt-3 mt-1">
      {!abierto && (
        <button
          onClick={() => setAbierto(true)}
          className="flex items-center gap-1.5 text-xs bg-[#121212] text-[#F1EBDD] px-3.5 py-2 rounded-lg hover:bg-[#1E1E1E] transition-colors"
        >
          <Plus size={13} /> Abrir nuevo proceso con {nombre.split(" ")[0]}
        </button>
      )}
      {abierto && (
        enviado ? (
          <p className="text-sm text-[#6B8F71] flex items-center gap-1.5">
            <CheckCircle2 size={15} /> Solicitud enviada — tu coach coordinará el nuevo ciclo con {nombre.split(" ")[0]}.
          </p>
        ) : (
          <div className="space-y-2">
            <p className="text-xs uppercase tracking-wide text-[#8A8270]">Nuevo proceso para {nombre}</p>
            <input value={cargo} onChange={(e) => setCargo(e.target.value)} placeholder="Cargo actual" className="w-full text-sm border border-[#E4DCC9] rounded-lg px-3 py-2 focus:outline-none focus:ring-2 focus:ring-[#6B8F71]/40" />
            <textarea
              value={objetivo}
              onChange={(e) => setObjetivo(e.target.value)}
              placeholder="¿Qué objetivo tienen en mente para este nuevo ciclo?"
              className="w-full text-sm border border-[#E4DCC9] rounded-xl p-3 h-16 resize-none focus:outline-none focus:ring-2 focus:ring-[#6B8F71]/40"
            />
            <div className="flex gap-2">
              <button onClick={() => setEnviado(true)} className="text-sm bg-[#121212] text-[#F1EBDD] px-4 py-2 rounded-lg hover:bg-[#1E1E1E] transition-colors">
                Enviar solicitud
              </button>
              <button onClick={() => setAbierto(false)} className="text-sm text-[#8A8270] hover:text-[#121212] px-2">Cancelar</button>
            </div>
          </div>
        )
      )}
    </div>
  );
}

