function GraficoProyeccion12Meses({ datos }) {
  const [seleccionado, setSeleccionado] = useState(datos[0].mes);
  const activo = datos.find((d) => d.mes === seleccionado);
  const fmt = (n) => `$${n.toLocaleString("es-CL")}`;

  return (
    <div className="bg-[#FEFCF8] rounded-2xl sm:rounded-3xl border border-[#E9DFC9] shadow-[0_4px_18px_rgba(107,79,45,0.08)] p-4 sm:p-5 h-full flex flex-col">
      <div className="flex items-start justify-between gap-2 flex-wrap mb-1">
        <div className="min-w-0">
          <p className="text-xs uppercase tracking-wide text-[#8A7A5C] leading-tight">Ingresos proyectados — 12 meses</p>
          <p className="text-[10px] text-[#B0A78E] mt-0.5">Toca una barra para ver el monto exacto</p>
        </div>
        <div className="text-right shrink-0">
          <p className="text-[10px] text-[#8A7A5C]">{activo.mes}</p>
          <p className="text-base font-mono text-[#121212] leading-none">{fmt(activo.monto)}</p>
        </div>
      </div>
      <div style={{ width: "100%", height: 120 }} className="mt-2 flex-1">
        <ResponsiveContainer>
          <BarChart data={datos} margin={{ top: 8, right: 2, left: -24, bottom: 0 }}>
            <CartesianGrid stroke="#EFE4D0" strokeDasharray="3 3" vertical={false} />
            <XAxis dataKey="mes" tick={{ fontSize: 8.5, fill: "#8A7A5C" }} axisLine={{ stroke: "#E9DFC9" }} tickLine={false} interval={1} />
            <YAxis tick={{ fontSize: 8.5, fill: "#8A7A5C" }} axisLine={false} tickLine={false} width={32} tickFormatter={(v) => `${Math.round(v / 1000)}k`} />
            <Tooltip formatter={(v) => fmt(v)} contentStyle={{ fontSize: 11, borderRadius: 8, borderColor: "#E9DFC9" }} cursor={{ fill: "rgba(193,104,59,0.08)" }} />
            <Bar
              dataKey="monto"
              radius={[4, 4, 0, 0]}
              cursor="pointer"
              onClick={(data) => setSeleccionado(data.mes)}
            >
              {datos.map((d, i) => (
                <Cell key={i} fill={d.mes === seleccionado ? "#C1683B" : "#E7D2BA"} />
              ))}
            </Bar>
          </BarChart>
        </ResponsiveContainer>
      </div>
    </div>
  );
}

function PanelFinancieroNegocio() {
  const { coachees, sesionesAgenda } = useCoaching();
  const [tab, setTab] = useState("cobros");

  const resumenCobros = calcularResumenCobros(coachees, sesionesAgenda);

  const ingresosDelMes = resumenCobros.filter((r) => r.estadoPago === "Pagado").reduce((a, r) => a + r.montoRealizadoMes, 0);
  const pendienteCobro = resumenCobros.filter((r) => r.estadoPago !== "Pagado").reduce((a, r) => a + r.monto, 0);
  const proyeccionMensual = resumenCobros.reduce((a, r) => a + r.monto, 0);
  const fmt = (n) => `$${n.toLocaleString("es-CL")}`;

  const tabs = [
    { id: "cobros", label: "Cobros" },
    { id: "sii", label: "SII y boletas" },
    { id: "payouts", label: "Cuenta de depósito" },
  ];

  return (
    <div className="space-y-4 sm:space-y-6">
      <div className="flex flex-wrap items-center justify-between gap-3">
        <div>
          <h2 className="text-lg sm:text-xl font-medium text-[#121212]" style={{ fontFamily: "Poppins, sans-serif", fontWeight: 700 }}>Negocio</h2>
          <p className="text-xs sm:text-sm text-[#8A7A5C] mt-0.5">Tus cobros, tus boletas y tu plata, todo en un solo lugar.</p>
        </div>
        <ExportarReporte
          datos={resumenCobros.map((r) => ({
            Empresa: r.nombre,
            Monto_mes: r.monto,
            Estado_pago: r.estadoPago,
            Fecha_cobro: r.fechaCobro,
            Medio_pago: r.medioPago,
            Documento: r.documento,
          }))}
          nombreArchivo="reporte-negocio"
        />
      </div>

      <GestionHoras />

      <div className="grid grid-cols-1 sm:grid-cols-2 gap-3 sm:gap-4">
        <KPINegocio titulo="Ingresos del mes" valor={fmt(ingresosDelMes)} color="#5C7A61" sub="empresas ya pagadas" />
        <KPINegocio
          titulo="Pendiente de cobro"
          valor={fmt(pendienteCobro)}
          color={TERRACOTA}
          sub="entre pendientes y atrasadas"
          accion={
            <button className="w-full flex items-center justify-center gap-1.5 text-xs text-white px-3 py-2 rounded-xl transition-colors" style={{ backgroundColor: TERRACOTA }}>
              <Send size={12} /> Recordar a todos
            </button>
          }
        />
        <KPINegocio titulo="Proyección mensual" valor={fmt(proyeccionMensual)} color="#121212" sub="según procesos activos" />
        <GraficoProyeccion12Meses datos={proyeccion12Meses} />
      </div>

      <div className="flex gap-1 bg-[#F3EADB] rounded-full p-1 w-fit">
        {tabs.map((t) => (
          <button
            key={t.id}
            onClick={() => setTab(t.id)}
            className={`text-xs sm:text-sm px-3.5 sm:px-4 py-1.5 rounded-full transition-colors whitespace-nowrap ${
              tab === t.id ? "bg-[#121212] text-[#F1EBDD]" : "text-[#8A7A5C] hover:text-[#121212]"
            }`}
          >
            {t.label}
          </button>
        ))}
      </div>

      {tab === "cobros" && <CobrosPorEmpresa resumenCobros={resumenCobros} />}
      {tab === "sii" && <ModuloTributarioSII />}
      {tab === "payouts" && <ConfiguracionPayouts />}
    </div>
  );
}

function GestionHoras() {
  const { coachees } = useCoaching();
  const porEmpresa = empresasConfig.map((emp) => {
    const coacheesEmpresa = coachees.filter((c) => c.empresa === emp.nombre);
    const satisfaccionProm = coacheesEmpresa.length
      ? (coacheesEmpresa.reduce((a, c) => a + c.satisfaccion, 0) / coacheesEmpresa.length).toFixed(1)
      : null;
    return {
      empresa: emp.nombre,
      contratadas: emp.horasContratadas,
      consumidas: coacheesEmpresa.reduce((a, c) => a + c.sesiones.hechas, 0),
      satisfaccionProm,
    };
  });
  return (
    <div className="bg-[#FDFBF7] rounded-2xl border border-[#EDE3D0] shadow-[0_3px_14px_rgba(90,68,40,0.07)] p-4 sm:p-5">
      <div className="flex items-center gap-2 mb-3 sm:mb-4">
        <Clock size={16} className="text-[#6B8F71]" />
        <h3 className="font-medium text-[#121212] text-sm sm:text-base">Horas contratadas vs. consumidas</h3>
      </div>
      <div className="space-y-4">
        {porEmpresa.map((e) => (
          <div key={e.empresa}>
            <div className="flex justify-between items-center text-sm mb-1.5">
              <span className="text-[#3A3226] flex items-center gap-1.5">
                {e.empresa}
                {e.satisfaccionProm && (
                  <span className="flex items-center gap-0.5 text-xs text-[#B08D57] font-mono">
                    <Star size={11} className="fill-[#B08D57] text-[#B08D57]" /> {e.satisfaccionProm}
                  </span>
                )}
              </span>
              <span className="font-mono text-[#6B8F71]">{e.consumidas}/{e.contratadas} hrs</span>
            </div>
            <ProgressBar value={Math.min(100, (e.consumidas / e.contratadas) * 100)} color="#B08D57" />
          </div>
        ))}
      </div>
    </div>
  );
}

