function ContratosConfidencialidad() {
  const { coachees } = useCoaching();
  const [verAcuerdo, setVerAcuerdo] = useState(null);

  return (
    <div className="bg-[#FDFBF7] rounded-2xl border border-[#EDE3D0] shadow-[0_3px_14px_rgba(90,68,40,0.07)] p-4 sm:p-5">
      <div className="flex items-center gap-2 mb-1">
        <Lock size={16} className="text-[#6B8F71]" />
        <h3 className="font-medium text-[#121212] text-sm sm:text-base">Contratos y acuerdos de confidencialidad</h3>
      </div>
      <p className="text-xs text-[#8A8270] mb-3">
        Estado del contrato y del acuerdo de confidencialidad por empresa. Esto respalda legalmente lo que la plataforma ya asume en cada pantalla.
      </p>
      <div className="space-y-2">
        {empresasConfig.map((e) => {
          const nConsentidos = coachees.filter((c) => c.empresa === e.nombre && c.consentimientoInformado).length;
          const nTotal = coachees.filter((c) => c.empresa === e.nombre).length;
          return (
            <div key={e.nombre} className="border border-[#E4DCC9] rounded-xl px-3.5 py-3">
              <div className="flex flex-wrap items-center justify-between gap-2 mb-1.5">
                <p className="text-sm font-medium text-[#121212]">{e.nombre}</p>
                <div className="flex items-center gap-1.5">
                  <span
                    className="text-xs font-medium px-2.5 py-1 rounded-full text-white"
                    style={{ backgroundColor: e.contrato.firmado ? "#6B8F71" : "#B0665B" }}
                  >
                    {e.contrato.firmado ? "Contrato firmado" : "Contrato pendiente"}
                  </span>
                  <span
                    className="text-xs font-medium px-2.5 py-1 rounded-full text-white"
                    style={{ backgroundColor: e.contrato.acuerdoConfidencialidad ? "#6B8F71" : "#B0665B" }}
                  >
                    {e.contrato.acuerdoConfidencialidad ? "NDA firmado" : "NDA pendiente"}
                  </span>
                </div>
              </div>
              <div className="flex flex-wrap items-center justify-between gap-2 text-xs text-[#8A8270]">
                <span>
                  {e.contrato.firmado ? `Firmado el ${e.contrato.fecha} · vigencia ${e.contrato.vigencia}` : "Aún no se firma contrato con esta empresa."}
                </span>
                <span>{nConsentidos}/{nTotal} coachees con consentimiento informado firmado</span>
              </div>
              <button
                onClick={() => setVerAcuerdo(verAcuerdo === e.nombre ? null : e.nombre)}
                className="text-xs text-[#6B8F71] hover:text-[#121212] mt-2 underline underline-offset-2"
              >
                {verAcuerdo === e.nombre ? "Ocultar acuerdo de confidencialidad" : "Ver acuerdo de confidencialidad"}
              </button>
              {verAcuerdo === e.nombre && (
                <p className="text-xs text-[#5C5340] leading-relaxed mt-2 bg-[#FBF9F4] border border-[#E4DCC9] rounded-lg p-3">
                  Acuerdo de confidencialidad entre Coach Fernando Ramos y {e.nombre}: el contenido de las sesiones
                  de coaching (conversación, notas y reflexiones del coachee) es estrictamente confidencial y no se
                  comparte con la empresa. Solo se reporta avance, resultados agregados y aquello que el coachee
                  autorice explícitamente compartir.
                </p>
              )}
            </div>
          );
        })}
      </div>
    </div>
  );
}

